<?php echo json_encode(DB::table("keterlambatan as kt")->join("siswa as s", "s.id", "=", "kt.siswa_id")->where("kt.status", 1)->select("s.nama_siswa", "kt.waktu_masuk as waktu", "kt.alasan as keterangan", DB::raw("\"Terlambat\" as jenis"))->orderByDesc("kt.waktu_masuk")->limit(2)->get()->concat(DB::table("absensi_detail as ad")->join("absensi as a", "a.id", "=", "ad.absensi_id")->join("siswa as s", "s.id", "=", "ad.siswa_id")->join("status_absensi as sa", "sa.id", "=", "ad.status_absensi_id")->whereIn("ad.status_absensi_id", [1, 2, 3, 4])->where("ad.status", 1)->where("a.status", 1)->select("s.nama_siswa", DB::raw("CONCAT(a.tanggal, \" 00:00:00\") as waktu"), "ad.keterangan as keterangan", "sa.keterangan as jenis")->orderByDesc("a.tanggal")->limit(2)->get())->sortByDesc("waktu")->values());
